function SpeakerAvatar({ speaker }: { speaker: Speaker }) {
  const hasPhoto = !!speaker.photo;
  return (
    <div className="flex flex-col items-center gap-2">
      {hasPhoto ? (
        <div className="w-[90px] h-[90px] rounded-full overflow-hidden bg-white/5 ring-2 ring-white/10">
          <img
            alt={speaker.name}
            src={speaker.photo}
            className="w-full h-full object-cover"
          />
        </div>
      ) : (
        <div className="w-[90px] h-[90px] rounded-full bg-white/5 border border-white/10 flex items-center justify-center">
          <span className="font-[var(--font-heading)] text-xl font-bold text-white/30">
            {speaker.name
              .split(" ")
              .map((n) => n[0])
              .join("")}
          </span>
        </div>
      )}
      <span className="font-[var(--font-body)] text-sm font-semibold text-white">
        {speaker.name}
      </span>
      {speaker.role && (
        <span className="font-[var(--font-body)] text-xs text-white/50 -mt-1">
          {speaker.role}
        </span>
      )}
    </div>
  );
}

